INSERT INTO `expense_ref_codes` VALUES (1,NULL,'2.1','ແຜນປະເມີນລາຍຈ່າຍບໍລິຫານປົກກະຕິ',0,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(2,NULL,'2.1.1','ບໍລິຫານສັງລວມ',1,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(3,NULL,'2.1.2','ບຳລຸງຮັກສາ, ສ້ອມແປງ ແລະ ຕິດຕັ້ງ',2,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(4,NULL,'2.1.3','ສ້ອມແປງ ແລະ ປັບປຸງອາຄານຫ້ອງຮຽນ',3,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(5,NULL,'2.1.4','ສ້ອມແປງພາຫານະ',4,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(6,NULL,'2.1.5','ຊື້ເຄື່ອງຈັກ, ວັດຖຸອຸປະກອນ',5,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(7,NULL,'2.1.6','ຄ່າປະກັນໄພພາຫະນະ',6,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(8,NULL,'2.1.7','ລາຍຈ່າຍໄປວຽກທາງການ',7,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(9,NULL,'2.1.8','ປົກປັກຮັກສາ ແລະ ອານາໄມອາຄານ, ສະຖານທີ່',8,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(10,NULL,'2.1.9','ວຽກງານກິດຈະກຳນັກສຶກສາ',9,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(11,NULL,'2.1.10','ລາຍຈ່າຍກອງປະຊຸມ, ສຳມະນາ ແລະ ຝຶກອົບຮົມ',10,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(12,NULL,'2.1.11','ລາຍຈ່າຍບໍລິຫານປົກກະຕິອື່ນໆ',11,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(13,NULL,'2.2','ແຜນປະເມີນລາຍຈ່າຍປັບປຸງ ແລະ ສົ່ງເສີມວິຊາການ',12,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(14,NULL,'2.2.1','ຊື້ວັດຖຸ, ອຸປະກອນການຮຽນ ແລະ ການສິດສອນ',13,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(15,NULL,'2.2.2','ປັບປຸງ ແລະ ພັດທະນາການສຶກສາ',14,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(16,NULL,'2.2.3','ບຳລຸງຫ້ອງທົດລອງ',15,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(17,NULL,'2.2.4','ຊື້ອຸປະກອນທົດລອງ',16,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(18,NULL,'2.3','ແຜນປະເມີນລາຍຈ່າຍດັດສົມ, ສົ່ງເສີມ ແລະ ບຳລຸງຮັກສາ',17,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(19,NULL,'2.3.1','ບໍລິຫານວິຊາການ',18,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(20,NULL,'2.3.2','ບູລະນະ ແລະ ປົກປັກຮັກສາວັດທະນະທຳ',19,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(21,NULL,'2.3.3','ໄປທັດສະນະສຶກສາ',20,'2026-05-27 18:39:05','2026-05-27 18:39:05'),(22,NULL,'2.4','